from __future__ import annotations

from io import StringIO
from math import ceil
from pathlib import Path
import base64
import gzip

import matplotlib.pyplot as plt
import numpy as np
import pandas as pd
import scienceplots  # noqa: F401
from matplotlib.colors import ListedColormap

# Frozen row-wise Muraro plotting data with t-SNE coordinates, ground truth,
# and per-method cluster assignments used in the all-method cluster panel figure.
FROZEN_SOURCE_B64 = """"""

ROOT = Path(__file__).resolve().parents[1]
OUT_DIR = ROOT / 'generated_figures'
OUT_DIR.mkdir(parents=True, exist_ok=True)

plt.style.use(["science", "nature", "no-latex"])
plt.rcParams.update({"figure.dpi": 200, "savefig.dpi": 300, "font.size": 8, "axes.titlesize": 9, "axes.labelsize": 8, "xtick.labelsize": 7, "ytick.labelsize": 7, "pdf.fonttype": 42, "ps.fonttype": 42})

METHOD_ORDER = ['Ground truth', 'scAGCR', 'Leiden', 'scDSC', 'scDCC', 'DEC', 'scMAE', 'scGPT-KMeans', 'scGPT-Leiden']
COL_MAP = {
    'Ground truth': 'cell_type',
    'scAGCR': 'scAGCR',
    'Leiden': 'Leiden',
    'scDSC': 'scDSC',
    'scDCC': 'scDCC',
    'DEC': 'DEC',
    'scMAE': 'scMAE',
    'scGPT-KMeans': 'scGPT_KMeans',
    'scGPT-Leiden': 'scGPT_Leiden',
}


def load_source_df() -> pd.DataFrame:
    raw = gzip.decompress(base64.b64decode(FROZEN_SOURCE_B64)).decode()
    return pd.read_csv(StringIO(raw))


def make_palette(n: int):
    base = plt.get_cmap('tab20')(np.linspace(0, 1, max(n, 20)))
    return ListedColormap(base[:n])


def align_cluster_colors(pred_labels, true_labels):
    true_cat = pd.Categorical(true_labels)
    true_codes = true_cat.codes
    mapping = {}
    for cluster in pd.unique(pred_labels):
        mask = pred_labels == cluster
        vals, cnts = np.unique(true_codes[mask], return_counts=True)
        mapping[cluster] = vals[np.argmax(cnts)]
    return np.array([mapping[c] for c in pred_labels]), len(true_cat.categories)


def plot_layout(df: pd.DataFrame, ncols: int, out_name: str):
    methods = METHOD_ORDER
    nrows = ceil(len(methods) / ncols)
    fig, axes = plt.subplots(nrows, ncols, figsize=(4.1 * ncols, 3.2 * nrows))
    axes = np.atleast_1d(axes).ravel()
    tsne = df[['tsne_1', 'tsne_2']].to_numpy()
    true_labels = df['cell_type'].to_numpy()
    true_codes = pd.Categorical(true_labels).codes
    true_n = len(pd.Categorical(true_labels).categories)
    for ax in axes[len(methods):]:
        ax.axis('off')
    for ax, method in zip(axes, methods):
        if method == 'Ground truth':
            color_codes = true_codes
            n = true_n
        else:
            pred = df[COL_MAP[method]].to_numpy()
            color_codes, n = align_cluster_colors(pred, true_labels)
        ax.scatter(tsne[:, 0], tsne[:, 1], c=color_codes, s=7, cmap=make_palette(n), linewidths=0, alpha=0.88)
        ax.set_title(method)
        ax.set_xticks([]); ax.set_yticks([])
        for spine in ax.spines.values():
            spine.set_visible(False)
    fig.tight_layout()
    fig.savefig(OUT_DIR / out_name, bbox_inches='tight')
    plt.close(fig)


def main():
    df = load_source_df()
    plot_layout(df, ncols=2, out_name='fig_case_muraro_clusters_2col.pdf')
    plot_layout(df, ncols=3, out_name='fig_case_muraro_clusters_3col.pdf')
    print(OUT_DIR / 'fig_case_muraro_clusters_2col.pdf')
    print(OUT_DIR / 'fig_case_muraro_clusters_3col.pdf')


if __name__ == '__main__':
    main()
